mapper.select:
SELECT l.id, l.user_id AS userId, l.operator_name AS operatorName,
       l.action, l.target_type AS targetType, l.target_id AS targetId, l.target_name AS targetName,
       l.ip_address AS ipAddress, l.remark,
       DATE_FORMAT(l.created_at, '%Y-%m-%d %H:%i:%s') AS createdAt
FROM operation_logs l
WHERE 1 = 1

    AND l.user_id = #{userId}


    AND l.action = #{action}


    AND l.target_type = #{targetType}


    AND l.created_at >= #{startTime}


    AND l.created_at <= #{endTime}

ORDER BY l.created_at DESC
